#include <stdio.h>

int main() {
    int diceRoll = 6;

    // Even though diceRoll starts at 6 (which is NOT < 5),
    // this code will definitely run once.
    do {
        printf("You rolled a %d!\n", diceRoll);
        diceRoll++;
    } while (diceRoll < 5);

    return 0;
}
